import{_ as r,o as t,c as s,j as a,a as n,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"奠基步法","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/武学基础/奠基步法.md","filePath":"4.资源分区/6.技艺及称号/武技类/武学基础/奠基步法.md"}'),d={name:"4.资源分区/6.技艺及称号/武技类/武学基础/奠基步法.md"};function p(_,e,l,i,c,h){return t(),s("div",null,[...e[0]||(e[0]=[a("h1",{id:"奠基步法",tabindex:"-1"},[n("奠基步法 "),a("a",{class:"header-anchor",href:"#奠基步法","aria-label":'Permalink to "奠基步法"'},"​")],-1),a("table",{class:"bannerparthead"},[a("tbody",null,[a("tr",{id:"hdr"},[a("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调019")])])],-1),o('<h1 id="奠基步法-1" tabindex="-1">奠基步法 <a class="header-anchor" href="#奠基步法-1" aria-label="Permalink to &quot;奠基步法&quot;">​</a></h1><p>奠基步法<br> D+500<br> 前置：武学基础-步法入门<br> 注1：此技艺遵循【武学总纲】<br> 厮杀争锋、奔逃亡命，如遇争斗，最【速】者便处于不败之地，籍于此，步法一脉便逐步发展，也有了超脱于其的内涵，而只论技法，无非【走】与【跃】耳，此法奠基最为容易，无需钻研费神，只需勤练便可有成，恒持之，或得逍遥。</p><p>兑换后可以修心步法精要，将开始：<br> *步法修行：每当修习者经历一个影片，其对步法的掌握便更进一步，愈发熟练的动作将使其增加五米的移速。</p><p>此外，修习者将得到一种基础的纵跃赶路之法，即：<br> *小纵跃功：使用时将消耗一点内力，用移动动作进行移动，本次移动若进行跳跃，如同已助跑一样进行处理，自由控制跳跃的落点和距离而无需检定，但每次跳跃的高度不能超过移动距离的1/2；回合结束时仍然需要站在稳固的落脚点上，否则就会坠落。</p><p>表现上视为运气内力连续纵跃数次到达目的地，同时在下蹲/伏地攀爬时也可正常移动，不受到此两者的移动减益效果影响。</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',7)])])}const f=r(d,[["render",p]]);export{m as __pageData,f as default};
